const body        = $input.first().json.body || {};
const intent      = (body.intent      || '').toLowerCase();
const plan        = body.plan         || null;
const paymentType = (body.paymentType || 'monthly').toLowerCase();
const buyer       = body.buyer        || {};

const buyerName     = (buyer.name     || '').trim();
const buyerLastName = (buyer.lastName || '').trim();
const buyerEmail    = (buyer.email    || '').toLowerCase().trim();

if (!buyerEmail) throw new Error('Email del comprador es requerido');
if (!plan)       throw new Error('Plan es requerido');

// ─── Frontend usa '-selecto'; Invoice Ninja usa '-ven' en custom_value3 ──
const SLUG_TO_IN = {
  'esencial-selecto':   'esencial-ven',
  'vanguardia-selecto': 'vanguardia-ven',
};
const planFamily = SLUG_TO_IN[plan] || plan;
const isVen      = planFamily.endsWith('-ven');

const PLAN_NAMES = {
  'esencial-zulia':   'Plan Esencial Zulia',
  'vanguardia-zulia': 'Plan Vanguardia Zulia',
  'esencial-ven':     'Plan Esencial Grupo Selecto',
  'vanguardia-ven':   'Plan Vanguardia Grupo Selecto',
};
const planName = PLAN_NAMES[planFamily] || plan;

// paymentType → custom_value2 de IN + frequency_id (4=mensual, 9=anual)
const frequencyLabel = paymentType === 'annual' ? 'Annualy' : 'Monthly';
const frequencyId    = paymentType === 'annual' ? 9 : 4;

// ─── Familiares afiliados ────────────────────────────────────────────────
const familyRaw = Array.isArray(body.family) ? body.family : [];
const family = familyRaw.map(f => ({
  name:      (f.name      || '').trim(),
  lastName:  (f.lastName  || '').trim(),
  cedula:    (f.cedula    || '').trim(),
  birthDate: (f.birthDate || '').trim(),
  relation:  (f.relation  || f.kinship || '').trim(),
})).filter(f => f.name || f.lastName);

const familyText = family.length === 0
  ? 'Sin familiares afiliados'
  : family.map((f, i) =>
      `${i+1}. ${f.name} ${f.lastName}` +
      (f.cedula    ? ` · CI: ${f.cedula}`     : '') +
      (f.birthDate ? ` · Nac: ${f.birthDate}` : '') +
      (f.relation  ? ` · ${f.relation}`       : '')
    ).join('\n');

const clientPrivateNotes =
  `[Wizard ${new Date().toISOString().split('T')[0]}] ${planName} (${paymentType})\n` +
  `Comprador: ${buyerName} ${buyerLastName} (CI: ${buyer.cedula || 's/CI'}, Tel: ${buyer.phone || 's/Tel'})\n` +
  (buyer.birthDate ? `Nacimiento: ${buyer.birthDate}\n` : '') +
  (buyer.zip       ? `ZIP: ${buyer.zip}\n`             : '') +
  `Familiares (${family.length}):\n${familyText}`;

return [{ json: {
  intent, plan, planFamily, planName, paymentType,
  isVen, frequencyLabel, frequencyId,
  buyer: {
    name:      buyerName,
    lastName:  buyerLastName,
    email:     buyerEmail,
    phone:     buyer.phone     || '',
    cedula:    buyer.cedula    || '',
    birthDate: buyer.birthDate || '',
    zip:       buyer.zip       || '',
  },
  family, familyText, clientPrivateNotes,
  timestamp:      body.timestamp || new Date().toISOString(),
  customerEmail:  buyerEmail,
  customerName:   (buyerName + ' ' + buyerLastName).trim(),
  firstName:      buyerName,
  lastName:       buyerLastName,
  customerPhone:  buyer.phone   || '',
  customerCedula: buyer.cedula  || '',
} }];

const inResponse = $input.first().json;
const ctx        = $('Parse & Validate Request').item.json;

const clientsArr = (inResponse.data && Array.isArray(inResponse.data)) ? inResponse.data : [];

const existing = clientsArr.find(c => {
  const contacts = c.contacts || [];
  return contacts.some(ct =>
    ct.email && ct.email.toLowerCase().trim() === ctx.customerEmail
  );
});

if (existing) {
  return [{ json: { ...ctx, clientId: existing.id, isNewClient: false } }];
} else {
  return [{ json: { ...ctx, clientId: null,        isNewClient: true  } }];
}

const inputJson = $input.first().json;
let clientId, ctx;

// Caso A: respuesta de Invoice Ninja al crear cliente (wrapper .data)
if (inputJson.data && inputJson.data.id) {
  clientId = inputJson.data.id;
  ctx      = $('Evaluate Client Exists').item.json;
}
// Caso A alternativo: IN devuelve objeto directo sin .data
else if (inputJson.id && !inputJson.planFamily) {
  clientId = inputJson.id;
  ctx      = $('Evaluate Client Exists').item.json;
}
// Caso B: cliente existente — el branch false ya trae clientId en el json
else if (inputJson.clientId) {
  clientId = inputJson.clientId;
  ctx      = inputJson;
}
else {
  throw new Error('No se pudo resolver clientId. Input: ' + JSON.stringify(inputJson));
}

if (!clientId) throw new Error('clientId es null o undefined');
return [{ json: { ...ctx, clientId } }];

const ctx = $input.first().json;

const BASE    = 'https://invoicing.legadoholding.com/api/v1';
const TOKEN   = '__INVOICE_NINJA_TOKEN__';
const HEADERS = { 'X-API-TOKEN': TOKEN, 'Accept': 'application/json' };

const httpReq = async (method, path, body) => {
  const opts = {
    method,
    url: BASE + path,
    headers: { ...HEADERS },
    json: true,
    returnFullResponse:    true,
    ignoreHttpStatusErrors: true,
  };
  if (body) {
    opts.body = JSON.stringify(body);
    opts.headers['Content-Type'] = 'application/json';
  }
  let r;
  try {
    r = await this.helpers.httpRequest(opts);
  } catch (e) {
    const s   = (e.response && e.response.status) || e.httpCode || 'unknown';
    const raw = (e.response && e.response.data) || e.body || e.cause || e.message;
    const m   = typeof raw === 'object' ? JSON.stringify(raw) : String(raw);
    throw new Error(`IN ${method} ${path} → ${s}: ${m}`);
  }
  const status = r.statusCode || r.status || 0;
  let parsed = (r.body !== undefined) ? r.body : r;
  if (typeof parsed === 'string') { try { parsed = JSON.parse(parsed); } catch (_) {} }
  if (status >= 400) {
    const m = typeof parsed === 'object' ? JSON.stringify(parsed) : String(parsed);
    throw new Error(`IN ${method} ${path} → ${status}: ${m}`);
  }
  return parsed;
};

// ── Catálogo de productos legadoweb ─────────────────────────────────────
const prodResp = await httpReq('GET', '/products?per_page=100');
const allProducts = (prodResp.data || []).filter(p =>
  !p.is_deleted && p.custom_value1 === 'legadoweb'
);

const familyProducts = allProducts.filter(p => p.custom_value3 === ctx.planFamily);
if (familyProducts.length === 0) {
  throw new Error(`Sin productos para familia '${ctx.planFamily}' (slug: '${ctx.plan}'). Revisar custom_value3.`);
}

let strategy, strategyLabel, lineItems1, lineItems2, frequencyId2;
let recurringProductId = '';   // UUID del producto recurrente (Monthly/Annualy)
let oneTimeProductId   = '';   // UUID del producto Unico (solo Selecto)
let recurringUnitPrice = 0;

if (ctx.isVen) {
  const unicoProd   = familyProducts.find(p => (p.custom_value2 || '').toLowerCase() === 'unico');
  const monthlyProd = familyProducts.find(p => (p.custom_value2 || '').toLowerCase() === 'monthly');
  if (!unicoProd)   throw new Error(`Producto 'Unico' no encontrado para '${ctx.planFamily}'`);
  if (!monthlyProd) throw new Error(`Producto 'Monthly' no encontrado para '${ctx.planFamily}'`);

  strategy      = 'ven';
  strategyLabel = 'Suscripción mensual (con cuota inicial)';
  lineItems1 = [
    { product_key: unicoProd.product_key,   notes: unicoProd.notes   || 'Cuota inicial del plan', cost: unicoProd.price,   qty: 1 },
    { product_key: monthlyProd.product_key, notes: 'Primer mes de mensualidad',                   cost: monthlyProd.price, qty: 1 },
  ];
  lineItems2          = [{ product_key: monthlyProd.product_key, notes: monthlyProd.notes || 'Mensualidad del plan', cost: monthlyProd.price, qty: 1 }];
  frequencyId2        = 4;
  recurringProductId  = monthlyProd.id;
  oneTimeProductId    = unicoProd.id;
  recurringUnitPrice  = monthlyProd.price;
} else {
  const targetProd = familyProducts.find(p =>
    (p.custom_value2 || '').toLowerCase() === ctx.frequencyLabel.toLowerCase()
  );
  if (!targetProd) throw new Error(`Producto no encontrado para '${ctx.planFamily}' con frecuencia '${ctx.frequencyLabel}'`);

  strategy      = ctx.paymentType === 'annual' ? 'zulia-annual'  : 'zulia-monthly';
  strategyLabel = ctx.paymentType === 'annual' ? 'Suscripción anual' : 'Suscripción mensual';
  lineItems1    = [{ product_key: targetProd.product_key, notes: targetProd.notes || '', cost: targetProd.price, qty: 1 }];
  lineItems2    = null;
  frequencyId2  = null;
  recurringProductId = targetProd.id;
  recurringUnitPrice = targetProd.price;
}

// ── Resolver / crear el Subscription template en Invoice Ninja ──────────
//    Convención de nombre: 'legadoweb-{planFamily}-{frequencyName}'
//    Esto permite que el mismo template se reuse para todos los clientes
//    del mismo plan + frecuencia.
const recurringFreqId  = ctx.isVen ? frequencyId2 : ctx.frequencyId;
const freqNameForName  = ctx.isVen ? 'monthly' : ctx.paymentType;
const subscriptionName = `legadoweb-${ctx.planFamily}-${freqNameForName}`;

const subsResp = await httpReq('GET', '/subscriptions?per_page=100');
const allSubs  = subsResp.data || [];
let subscription = allSubs.find(s => s.name === subscriptionName && !s.is_deleted);

if (!subscription) {
  // Intentar auto-crear el Subscription template. Si IN falla (500/422/etc.)
  // NO rompemos el flujo: el subscription_id es solo un link visual en el
  // portal del cliente; la recurring invoice cobra recurrente igualmente.
  const subBody = {
    name:                            subscriptionName,
    recurring_product_ids:           recurringProductId,
    product_ids:                     oneTimeProductId || '',
    optional_product_ids:            '',
    optional_recurring_product_ids:  '',
    frequency_id:                    recurringFreqId,
    auto_bill:                       'off',
    promo_code:                      '',
    promo_discount:                  0,
    is_amount_discount:              false,
    allow_cancellation:              true,
    per_seat_enabled:                false,
    max_seats_limit:                 0,
    trial_enabled:                   false,
    trial_duration:                  0,
    allow_query_overrides:           false,
    allow_plan_changes:              false,
    refund_period:                   0,
    use_inventory_management:        false,
    registration_required:           false,
    plan_map:                        '',
    steps:                           'cart,checkout',
    webhook_configuration: {
      post_purchase_url:           '',
      post_purchase_rest_method:   '',
      post_purchase_headers:       [],
      post_purchase_body:          '',
      return_url:                  ''
    },
  };

  try {
    const createSub = await httpReq('POST', '/subscriptions', subBody);
    subscription = createSub.data || createSub;
    if (!subscription || !subscription.id) subscription = null;
  } catch (e) {
    // IN rechazó la creación. Loguear y continuar sin subscription_id.
    console.warn('Auto-creación del Subscription falló; continuando sin link:', e.message);
    subscription = null;
  }
}

return [{ json: {
  ...ctx,
  strategy, strategyLabel,
  lineItems1, lineItems2, frequencyId2,
  subscriptionId:   subscription ? subscription.id : null,
  subscriptionName,
} }];

const ctx = $input.first().json;

const BASE    = 'https://invoicing.legadoholding.com/api/v1';
const TOKEN   = '__INVOICE_NINJA_TOKEN__';
const HEADERS = { 'X-API-TOKEN': TOKEN, 'Content-Type': 'application/json', 'Accept': 'application/json' };

const httpReq = async (method, path, body) => {
  const opts = {
    method,
    url: BASE + path,
    headers: { ...HEADERS },
    json: true,
    returnFullResponse:    true,
    ignoreHttpStatusErrors: true,
  };
  if (body) opts.body = JSON.stringify(body);
  let r;
  try {
    r = await this.helpers.httpRequest(opts);
  } catch (e) {
    const s   = (e.response && e.response.status) || e.httpCode || 'unknown';
    const raw = (e.response && e.response.data) || e.body || e.cause || e.message;
    const m   = typeof raw === 'object' ? JSON.stringify(raw) : String(raw);
    throw new Error(`IN ${method} ${path} → ${s}: ${m}`);
  }
  const status = r.statusCode || r.status || 0;
  let parsed = (r.body !== undefined) ? r.body : r;
  if (typeof parsed === 'string') { try { parsed = JSON.parse(parsed); } catch (_) {} }
  if (status >= 400) {
    const m = typeof parsed === 'object' ? JSON.stringify(parsed) : String(parsed);
    throw new Error(`IN ${method} ${path} → ${status}: ${m}`);
  }
  return parsed;
};

const toLineItems = (items) => items.map(li => ({
  product_key: li.product_key,
  notes:       li.notes || '',
  cost:        li.cost,
  quantity:    li.qty   || 1,
}));

const sleep = (ms) => new Promise(r => setTimeout(r, ms));

// Total del primer ciclo (incluye Unico en Selecto)
const invoiceTotal = ctx.lineItems1
  .reduce((sum, li) => sum + (li.cost * (li.qty || 1)), 0)
  .toFixed(2);

const publicNotes =
  `${ctx.planName} — ${ctx.strategyLabel}\n` +
  `Titular: ${ctx.customerName}\n` +
  `Familiares afiliados (${ctx.family.length}/6):\n${ctx.familyText}`;

const today = new Date().toISOString().split('T')[0];

// Frecuencia recurrente: Selecto siempre mensual (frequencyId2),
// Zulia respeta la elección del cliente (frequencyId 4 ó 9).
const recurringFreqId = ctx.isVen ? ctx.frequencyId2 : ctx.frequencyId;

// ── 1. Crear la suscripción (Recurring Invoice) con los items del primer
//      ciclo. Para Selecto: Unico + Monthly. Para Zulia: Monthly o Annualy.
const recurringBody = {
  client_id:        ctx.clientId,
  frequency_id:     recurringFreqId,
  status_id:        2,        // 2 = active → se procesa por cron / send_now
  auto_bill:        'off',    // pago manual vía enlace
  next_send_date:   today,
  remaining_cycles: -1,       // sin límite
  line_items:       toLineItems(ctx.lineItems1),
  public_notes:     publicNotes,
};
// Linkear al Subscription template solo si está disponible (puede ser null
// si la auto-creación falló o si aún no se ha creado manualmente en IN).
if (ctx.subscriptionId) recurringBody.subscription_id = ctx.subscriptionId;

const recResp   = await httpReq('POST', '/recurring_invoices', recurringBody);
const recurring = recResp.data || recResp;
const recurringId = recurring.id;
if (!recurringId) {
  throw new Error('Error creando suscripción: ' + JSON.stringify(recResp));
}

// ── 2. Forzar la generación inmediata del primer invoice ───────────────
await httpReq('POST', '/recurring_invoices/bulk', {
  action: 'send_now',
  ids:    [recurringId],
});

// ── 3. Polling para encontrar el invoice generado (hasta ~8s) ──────────
let firstInvoice = null;
for (let attempt = 0; attempt < 10 && !firstInvoice; attempt++) {
  await sleep(800);
  const listResp = await httpReq('GET',
    `/invoices?client_id=${ctx.clientId}&per_page=20&sort=id|desc`);
  const list = (listResp.data || [])
    .filter(inv => inv.recurring_id === recurringId);
  if (list.length > 0) firstInvoice = list[0];
}

if (!firstInvoice || !firstInvoice.id) {
  throw new Error(`Factura inicial no generada (recurring_id=${recurringId}). Verifica el cron de Invoice Ninja.`);
}

// ── 4. Para Selecto: quitar 'Unico' de la suscripción para que los
//      ciclos siguientes solo cobren la mensualidad.
if (ctx.isVen && ctx.lineItems2) {
  await httpReq('PUT', `/recurring_invoices/${recurringId}`, {
    line_items: toLineItems(ctx.lineItems2),
  });
}

// ── 5. Obtener el enlace de invitación del invoice generado ────────────
const invFull = await httpReq('GET', `/invoices/${firstInvoice.id}?include=invitations`);
const invData = invFull.data || invFull;
const invLink = (invData.invitations && invData.invitations[0])
  ? invData.invitations[0].link
  : '';

return [{ json: {
  ...ctx,
  recurringId,
  invoiceId:      firstInvoice.id     || '',
  invoiceNumber:  firstInvoice.number || invData.number || '',
  invitationLink: invLink,
  invoiceTotal,
} }];

