<html lang="es">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <style>
    body { margin:0; padding:0; font-family: Arial, sans-serif; color:#3b3b3b; background:#f9f9f9; }
    .container { max-width:600px; margin:0 auto; background:#fff; border:1px solid #e0e0e0; border-radius:8px; overflow:hidden; }
    .header { padding:30px 0; text-align:center; background:#fff; }
    .header img { max-width:220px; height:auto; }
    .body { padding:24px 40px; }
    h1 { font-size:24px; color:#3b3b3b; margin:0 0 16px; text-align:center; font-weight:600; }
    p { font-size:15px; line-height:1.6; color:#555; }
    table.summary { width:100%; border-collapse:collapse; margin:24px 0; }
    table.summary td { padding:10px 0; border-bottom:1px solid #eee; font-size:14px; }
    table.summary td:first-child { color:#888; }
    table.summary td:last-child { text-align:right; font-weight:600; }
    .total td { color:#c8a05a; font-size:17px; }
    .members { background:#fafafa; padding:14px 18px; border-radius:6px; margin:12px 0 24px; font-size:13px; color:#555; white-space:pre-wrap; }
    .cta { text-align:center; margin:32px 0; }
    .button { background:#c8a05a; color:#fff !important; text-decoration:none; padding:14px 36px; border-radius:4px; font-weight:bold; font-size:15px; display:inline-block; }
    .link-fallback { font-size:12px; color:#999; text-align:center; word-break:break-all; }
    .link-fallback a { color:#c8a05a; }
    .help { background:#c8a05a; padding:24px; text-align:center; color:#fff; }
    .help h2 { font-size:17px; margin:0; font-weight:500; }
    .help p { font-size:13px; opacity:0.9; margin:8px 0 0; color:#fff; }
    .footer { background:#242424; padding:18px; text-align:center; color:#999; font-size:11px; }
  </style>
</head>
<body>
  <div style="padding:20px 0;">
    <div class="container">
      <div class="header">
        <img src="https://legadoholding.com/images/LogoLegado.png" alt="Legado Holding LLC">
      </div>
      <div class="body">
        <h1>¡Tu solicitud fue registrada!</h1>
        <p>Hola <strong>{{ $json.customerName }}</strong>,<br>
        hemos registrado tu afiliación al <strong>{{ $json.planName }}</strong>.
        La factura <strong>{{ $json.invoiceNumber }}</strong> ya está disponible para pago seguro.</p>

        <table class="summary">
          <tr><td>Plan</td><td>{{ $json.planName }}</td></tr>
          <tr><td>Modalidad</td><td>{{ $json.strategyLabel }}</td></tr>
