        <div class="members">{{ $json.familyText }}</div>

        <div class="cta">
          <a href="{{ $json.invitationLink }}" class="button">PAGAR FACTURA AHORA</a>
        </div>
        <p class="link-fallback">Si el botón no funciona, copia este enlace:<br>
          <a href="{{ $json.invitationLink }}">{{ $json.invitationLink }}</a>
        </p>
      </div>
      <div class="help">
        <h2>¿Necesitas ayuda?</h2>
        <p>Escríbenos a <a href="mailto:info@legadoholding.com" style="color:#fff;">info@legadoholding.com</a></p>
      </div>
      <div class="footer">
        &copy; 2026 Legado Holding LLC · Mensaje automático
      </div>
    </div>
  </div>
</body>
